import express from "express";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PORT = process.env.PORT || 3456;
const QUERY = "영화 상영업";
const RSS_URL = `https://news.google.com/rss/search?q=${encodeURIComponent(QUERY)}&hl=ko&gl=KR&ceid=KR:ko`;
const MAX_ITEMS = 5;

const app = express();
app.use(express.static(__dirname));

function decodeXml(text) {
  return text
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, "$1")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .trim();
}

function extractTag(block, tag) {
  const re = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, "i");
  const match = block.match(re);
  return match ? decodeXml(match[1]) : "";
}

function parseRss(xml) {
  const items = [];
  const itemRegex = /<item>([\s\S]*?)<\/item>/gi;
  let match;

  while ((match = itemRegex.exec(xml)) !== null && items.length < MAX_ITEMS) {
    const block = match[1];
    const title = extractTag(block, "title");
    const link = extractTag(block, "link");
    const pubDate = extractTag(block, "pubDate");
    const source = extractTag(block, "source");

    if (title && link) {
      items.push({ title, link, pubDate, source: source || null });
    }
  }

  return items;
}

app.get("/api/news", async (_req, res) => {
  try {
    const response = await fetch(RSS_URL, {
      headers: {
        "User-Agent":
          "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        Accept: "application/rss+xml, application/xml, text/xml, */*",
      },
    });

    if (!response.ok) {
      res.status(502).json({ error: "Google News RSS를 가져오지 못했습니다." });
      return;
    }

    const xml = await response.text();
    const items = parseRss(xml);

    if (items.length === 0) {
      res.status(404).json({ error: "검색 결과가 없습니다." });
      return;
    }

    res.json({
      query: QUERY,
      source: "Google News",
      fetchedAt: new Date().toISOString(),
      items,
    });
  } catch {
    res.status(500).json({ error: "뉴스를 불러오는 중 오류가 발생했습니다." });
  }
});

app.listen(PORT, () => {
  console.log(`영화 상영업 뉴스 앱: http://localhost:${PORT}`);
});

const statusEl = document.getElementById("status");
const newsListEl = document.getElementById("news-list");
const errorCardEl = document.getElementById("error-card");
const errorMessageEl = document.getElementById("error-message");
const footerMetaEl = document.getElementById("footer-meta");
const btnRefresh = document.getElementById("btn-refresh");

function formatDate(isoOrRss) {
  if (!isoOrRss) return "";
  const date = new Date(isoOrRss);
  if (Number.isNaN(date.getTime())) return isoOrRss;
  return date.toLocaleString("ko-KR", {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function splitTitleSource(title) {
  const dash = title.lastIndexOf(" - ");
  if (dash === -1) return { headline: title, outlet: null };
  return {
    headline: title.slice(0, dash),
    outlet: title.slice(dash + 3),
  };
}

function createNewsCard(item, index) {
  const li = document.createElement("li");
  li.className = "news-card";
  li.style.animationDelay = `${index * 70}ms`;

  const { headline, outlet } = splitTitleSource(item.title);
  const source = item.source || outlet;

  const rank = document.createElement("span");
  rank.className = "news-rank";
  rank.textContent = String(index + 1);

  const body = document.createElement("div");
  body.className = "news-body";

  const link = document.createElement("a");
  link.className = "news-title";
  link.href = item.link;
  link.target = "_blank";
  link.rel = "noopener noreferrer";
  link.textContent = headline;

  const meta = document.createElement("p");
  meta.className = "news-meta";

  if (source) {
    const sourceSpan = document.createElement("span");
    sourceSpan.className = "news-source";
    sourceSpan.textContent = source;
    meta.appendChild(sourceSpan);
  }

  if (item.pubDate) {
    const time = document.createElement("time");
    time.dateTime = new Date(item.pubDate).toISOString();
    time.textContent = formatDate(item.pubDate);
    meta.appendChild(time);
  }

  body.appendChild(link);
  if (meta.childElementCount > 0) body.appendChild(meta);

  const arrow = document.createElement("span");
  arrow.className = "news-arrow";
  arrow.setAttribute("aria-hidden", "true");
  arrow.textContent = "→";

  li.append(rank, body, arrow);
  return li;
}

function setLoading(loading) {
  btnRefresh.disabled = loading;
  btnRefresh.classList.toggle("btn--loading", loading);
}

function showError(message) {
  newsListEl.hidden = true;
  errorCardEl.hidden = false;
  errorMessageEl.textContent = message;
  statusEl.textContent = "뉴스를 불러오지 못했습니다.";
  statusEl.classList.add("status--error");
}

function showNews(data) {
  errorCardEl.hidden = true;
  statusEl.classList.remove("status--error");

  newsListEl.replaceChildren();
  data.items.forEach((item, i) => {
    newsListEl.appendChild(createNewsCard(item, i));
  });

  newsListEl.hidden = false;
  statusEl.textContent = `최신 기사 ${data.items.length}건 · ${formatDate(data.fetchedAt)} 기준`;
  footerMetaEl.textContent = `데이터 출처: ${data.source} · 검색어: ${data.query}`;
}

async function loadNews() {
  setLoading(true);
  statusEl.textContent = "Google 뉴스에서 검색 중…";
  statusEl.classList.remove("status--error");
  errorCardEl.hidden = true;
  newsListEl.hidden = true;

  try {
    const res = await fetch("/api/news");
    const data = await res.json();

    if (!res.ok) {
      showError(data.error || "알 수 없는 오류가 발생했습니다.");
      return;
    }

    showNews(data);
  } catch {
    showError("서버에 연결할 수 없습니다. npm start로 앱을 실행해 주세요.");
  } finally {
    setLoading(false);
  }
}

btnRefresh.addEventListener("click", loadNews);
loadNews();

:root {
  --bg: #0a0b10;
  --surface: #12141c;
  --surface-hover: #1a1d28;
  --border: rgba(255, 255, 255, 0.07);
  --text: #eef0f6;
  --text-muted: #8b93a8;
  --accent: #e8b84a;
  --accent-soft: rgba(232, 184, 74, 0.15);
  --cinema-red: #c43d4a;
  --cinema-red-soft: rgba(196, 61, 74, 0.2);
  --radius: 16px;
  --shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
  font-family: "Noto Sans KR", system-ui, sans-serif;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

.bg-glow {
  position: fixed;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 70% 45% at 50% -5%, var(--cinema-red-soft), transparent 55%),
    radial-gradient(ellipse 50% 35% at 100% 100%, var(--accent-soft), transparent 50%);
}

.bg-grain {
  position: fixed;
  inset: 0;
  pointer-events: none;
  opacity: 0.04;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
}

.app {
  position: relative;
  max-width: 680px;
  margin: 0 auto;
  padding: 2.5rem 1.25rem 3rem;
}

.header {
  text-align: center;
  margin-bottom: 2rem;
}

.eyebrow {
  margin: 0 0 0.5rem;
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--cinema-red);
}

h1 {
  margin: 0 0 0.75rem;
  font-size: clamp(1.75rem, 5vw, 2.35rem);
  font-weight: 700;
  letter-spacing: -0.03em;
}

.subtitle {
  margin: 0;
  font-size: 0.95rem;
  color: var(--text-muted);
  max-width: 34em;
  margin-inline: auto;
}

.subtitle strong {
  color: var(--text);
  font-weight: 500;
}

.toolbar {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.query-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.45rem 0.9rem;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--accent);
  background: var(--accent-soft);
  border: 1px solid rgba(232, 184, 74, 0.25);
  border-radius: 999px;
}

.query-badge::before {
  content: "⌕";
  font-size: 0.9rem;
  opacity: 0.8;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.6rem 1.1rem;
  font-family: inherit;
  font-size: 0.88rem;
  font-weight: 600;
  color: var(--text);
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  cursor: pointer;
  transition: background 0.15s, transform 0.15s, opacity 0.15s;
}

.btn:hover:not(:disabled) {
  background: var(--surface-hover);
}

.btn:active:not(:disabled) {
  transform: scale(0.97);
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn--loading .btn-icon {
  display: inline-block;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.status {
  margin: 0 0 1rem;
  font-size: 0.85rem;
  color: var(--text-muted);
  text-align: center;
}

.status--error {
  color: #ff8787;
}

.news-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.news-card {
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 1rem;
  padding: 1.1rem 1.15rem;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  transition: border-color 0.2s, background 0.2s, transform 0.2s;
  animation: slideIn 0.45s cubic-bezier(0.22, 1, 0.36, 1) backwards;
}

.news-card:hover {
  background: var(--surface-hover);
  border-color: rgba(232, 184, 74, 0.2);
  transform: translateY(-2px);
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.news-rank {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--bg);
  background: linear-gradient(145deg, #f0d078, var(--accent));
  border-radius: 8px;
  flex-shrink: 0;
}

.news-body {
  min-width: 0;
}

.news-title {
  display: block;
  font-size: 1rem;
  font-weight: 600;
  line-height: 1.45;
  color: var(--text);
  text-decoration: none;
  margin-bottom: 0.35rem;
}

.news-title:hover {
  color: var(--accent);
}

.news-meta {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.5rem 0.75rem;
  margin: 0;
  font-size: 0.78rem;
  color: var(--text-muted);
}

.news-source {
  padding: 0.15rem 0.5rem;
  background: var(--cinema-red-soft);
  color: #f0a0a8;
  border-radius: 4px;
  font-weight: 500;
}

.news-meta time::before {
  content: "· ";
  opacity: 0.5;
}

.news-arrow {
  font-size: 1.1rem;
  color: var(--text-muted);
  opacity: 0.4;
  transition: opacity 0.2s, transform 0.2s;
}

.news-card:hover .news-arrow {
  opacity: 1;
  color: var(--accent);
  transform: translateX(3px);
}

.error-card {
  padding: 1.25rem 1.35rem;
  background: rgba(196, 61, 74, 0.1);
  border: 1px solid rgba(196, 61, 74, 0.35);
  border-radius: var(--radius);
  margin-bottom: 1.5rem;
}

.error-card h2 {
  margin: 0 0 0.5rem;
  font-size: 1rem;
  color: #ff8787;
}

.error-card p {
  margin: 0;
  font-size: 0.9rem;
  color: var(--text-muted);
}

.error-hint {
  margin-top: 0.75rem !important;
}

.error-card code {
  font-family: "JetBrains Mono", Consolas, monospace;
  font-size: 0.82rem;
  color: var(--text);
  background: rgba(0, 0, 0, 0.25);
  padding: 0.1rem 0.35rem;
  border-radius: 4px;
}

.footer {
  margin-top: 2rem;
  text-align: center;
  font-size: 0.78rem;
  color: var(--text-muted);
}

@media (max-width: 480px) {
  .news-card {
    grid-template-columns: auto 1fr;
  }

  .news-arrow {
    display: none;
  }
}

